import json,statistics as st
P=json.load(open('panel.json')); SYS=sorted({r['sys'] for r in P})
F=['words','sections','h3','headings_per_1k','med_para','bullets_per_1k','tables','table_rows_per_1k','hedge_per_1k','studies_per_1k']
def pear(x,y):
    mx,my=st.mean(x),st.mean(y); n=sum((a-mx)*(b-my) for a,b in zip(x,y))
    d=(sum((a-mx)**2 for a in x)*sum((b-my)**2 for b in y))**.5
    return n/d if d>1e-12 else 0.
def fe(sub,k,dim):
    S=sorted({r['sys'] for r in sub}); T=sorted({r['task'] for r in sub})
    gmf=st.mean([r[k] for r in sub]); gmd=st.mean([r[dim] for r in sub])
    smf={s:st.mean([r[k] for r in sub if r['sys']==s]) for s in S}
    smd={s:st.mean([r[dim] for r in sub if r['sys']==s]) for s in S}
    tmf={t:st.mean([r[k] for r in sub if r['task']==t]) for t in T}
    tmd={t:st.mean([r[dim] for r in sub if r['task']==t]) for t in T}
    x=[r[k]-smf[r['sys']]-tmf[r['task']]+gmf for r in sub]
    y=[r[dim]-smd[r['sys']]-tmd[r['task']]+gmd for r in sub]
    return pear(x,y)
print('2-way FE (task+system) corr with OVERALL, split by language')
print(f\"{'feature':<18}{'ALL':>8}{'EN':>8}{'ZH':>8}\")
for k in F:
    r=[fe([x for x in P if f(x)],k,'overall_score') for f in [lambda r:True, lambda r: not r['zh'], lambda r: r['zh']]]
    print(f'{k:<18}'+''.join(f'{v:>8.2f}' for v in r))
print()
print('2-way FE with READABILITY')
print(f\"{'feature':<18}{'ALL':>8}{'EN':>8}{'ZH':>8}\")
for k in F:
    r=[fe([x for x in P if f(x)],k,'readability') for f in [lambda r:True, lambda r: not r['zh'], lambda r: r['zh']]]
    print(f'{k:<18}'+''.join(f'{v:>8.2f}' for v in r))
